fn pow_mod(mut base: i64, mut exp: i64, modulus: i64) -> i64 {
    if modulus == 1 {
        return 0;
    }
    base %= modulus;
    let mut result = 1;
    while exp > 0 {
        if exp % 2 == 1 {
            result = (result * base) % modulus;
        }
        exp >>= 1;
        base = (base * base) % modulus;
    }
    result
}

fn mod_inverse(a: i64, modulus: i64) -> i64 {
    pow_mod(a, modulus - 2, modulus)
}

pub fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    let mod_val: i64 = 1_000_000_007;
    let n = nums.len();
    let B = (n as f64).sqrt() as usize;
    let mut current_arr = nums.clone();

    let mut small_diff: Vec<Vec<Vec<i64>>> = vec![vec![]; B + 1];
    for k_val in 1..=B {
        small_diff[k_val] = vec![vec![]; k_val];
        for r0 in 0..k_val {
            if r0 < n {
                let residue_class_size = (n - 1 - r0) / k_val + 1;
                small_diff[k_val][r0] = vec![1; residue_class_size + 1];
            } else {
                small_diff[k_val][r0] = vec![1; 1];
            }
        }
    }

    for query in &queries {
        let l = query[0] as usize;
        let r = query[1] as usize;
        let k_val = query[2] as usize;
        let v = query[3];

        if k_val > B {
            let mut idx = l;
            while idx <= r {
                current_arr[idx] = (current_arr[idx] * v) % mod_val;
                if r - idx < k_val {
                    break;
                }
                idx += k_val;
            }
        } else if k_val > 0 && k_val < small_diff.len() {
            let r0 = l % k_val;
            if r0 < small_diff[k_val].len() {
                let t0 = if l <= r0 { 0 } else { (l - r0 + k_val - 1) / k_val };
                let t_max = if r < r0 { 0 } else { (r - r0) / k_val };
                if t0 <= t_max {
                    let residue_class = &mut small_diff[k_val][r0];
                    let residue_class_size = residue_class.len() - 1;
                    if t0 < residue_class_size && t0 <= t_max {
                        residue_class[t0] = (residue_class[t0] * v) % mod_val;
                        let t_end = t_max + 1;
                        if t_end < residue_class.len() {
                            let inv_v = mod_inverse(v, mod_val);
                            residue_class[t_end] = (residue_class[t_end] * inv_v) % mod_val;
                        }
                    }
                }
            }
        }
    }

    let mut small_factor_arr = vec![1; n];
    for k_val in 1..=B {
        if k_val >= small_diff.len() {
            continue;
        }
        for r0 in 0..small_diff[k_val].len() {
            let residue_class = &small_diff[k_val][r0];
            let residue_class_size = residue_class.len() - 1;
            if residue_class_size == 0 {
                continue;
            }
            let mut prod = 1;
            for t in 0..residue_class_size {
                prod = (prod * residue_class[t]) % mod_val;
                let idx = r0 + t * k_val;
                if idx < n {
                    small_factor_arr[idx] = (small_factor_arr[idx] * prod) % mod_val;
                }
            }
        }
    }

    for i in 0..n {
        current_arr[i] = (current_arr[i] * small_factor_arr[i]) % mod_val;
    }

    current_arr.iter().fold(0, |acc, &x| acc ^ x)
}
