            }
            let residue = l % k_usize;
            let list = &residue_lists[k_usize][residue];
            if list.is_empty() {
                continue;
            }

            let first_greater_than_r = list.partition_point(|&x| x <= r);
            if first_greater_than_r == 0 {
                continue;
            }
            let R_index = first_greater_than_r - 1;

            let L_index = list.partition_point(|&x| x < l);
            if L_index >= list.len() || L_index > R_index {
                continue;
            }

            residue_deltas[k_usize][residue][L_index] = (residue_deltas[k_usize][residue][L_index] * v) % MOD;
            if R_index + 1 < residue_deltas[k_usize][residue].len() {
                let inv_v = mod_inverse(v, MOD);
                residue_deltas[k_usize][residue][R_index + 1] = (residue_deltas[k_usize][residue][R_index + 1] * inv_v) % MOD;
            }
        }
