    for k in 1..K {
        for residue in 0..k {
            let list = &residue_lists[k][residue];
            let deltas = &residue_deltas[k][residue];
            let mut factor = 1;
            for j in 0..list.len() {
                factor = (factor * deltas[j]) % MOD;
                let orig_idx = list[j];
                total_factor[orig_idx] = (total_factor[orig_idx] * factor) % MOD;
            }
        }
    }

    let mut xor = 0;
    for i in 0..n {
        let value = (nums[i] * total_factor[i]) % MOD;
        xor ^= value;
    }
    xor
}
