const MOD: i64 = 1_000_000_007;

fn mod_inverse(a: i64, modulus: i64) -> i64 {
    let mut a = a % modulus;
    if a < 0 {
        a += modulus;
    }
    let mut res = 1;
    let mut base = a;
    let mut exp = modulus - 2;
    while exp > 0 {
        if exp & 1 == 1 {
            res = res * base % modulus;
        }
        base = base * base % modulus;
        exp >>= 1;
    }
    res
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    let n = nums.len();
    let mut total_mult = vec![1; n];
    let s = (n as f64).sqrt().ceil() as usize;

    let mut large_queries = Vec::new();
    let mut small_queries_map = std::collections::HashMap::new();

    for q in queries {
        let l = q[0] as usize;
        let r = q[1] as usize;
        let k = q[2] as usize;
        let v = q[3] % MOD;
        if k >= s {
            large_queries.push((l, r, k, v));
        } else {
            small_queries_map.entry(k).or_insert_with(Vec::new).push((l, r, k, v));
        }
    }

    for (l, r, k, v) in large_queries {
        let mut idx = l;
        while idx <= r {
            total_mult[idx] = (total_mult[idx] * v) % MOD;
            idx += k;
        }
    }

    for (k, queries_for_k) in small_queries_map {
        let mut residue_classes: Vec<Vec<usize>> = vec![Vec::new(); k];
        for i in 0..n {
            residue_classes[i % k].push(i);
        }

        let mut residue_queries = std::collections::HashMap::new();
        for &(l, r_val, _, v_val) in &queries_for_k {
            let residue = l % k;
            residue_queries.entry(residue).or_insert_with(Vec::new).push((l, r_val, v_val));
        }

        for (residue, q_list) in residue_queries {
            if residue >= residue_classes.len() {
                continue;
            }
            let indices = &residue_classes[residue];
            let m = indices.len();
            if m == 0 {
                continue;
            }
            let mut events = vec![1; m + 1];

            for &(l, r_val, v_val) in &q_list {
                let start_pos = match indices.binary_search(&l) {
                    Ok(pos) => pos,
                    Err(pos) => pos,
                };
                if start_pos >= m {
                    continue;
                }
                let end_pos = match indices.binary_search(&r_val) {
                    Ok(pos) => pos,
                    Err(pos) => if pos == 0 { continue; } else { pos - 1 },
                };
                if end_pos < start_pos {
                    continue;
                }
                events[start_pos] = (events[start_pos] * v_val) % MOD;
                if end_pos + 1 < m + 1 {
                    events[end_pos + 1] = (events[end_pos + 1] * mod_inverse(v_val, MOD)) % MOD;
                }
            }

            let mut cur = 1;
            for j in 0..m {
                cur = (cur * events[j]) % MOD;
                let orig_index = indices[j];
                total_mult[orig_index] = (total_mult[orig_index] * cur) % MOD;
            }
        }
    }

    let mut result_xor = 0;
    for i in 0..n {
        let updated = nums[i] * total_mult[i] % MOD;
        result_xor ^= updated;
    }

    result_xor
}
